/* eslint-disable complexity, @typescript-eslint/prefer-nullish-coalescing, @typescript-eslint/no-unused-expressions, @typescript-eslint/non-nullable-type-assertion-style -- cohesive workflow pages intentionally keep related governed state adjacent. */
/* Page implementations share state primitives so every workflow presents the same governed failure semantics. */
import { useMemo, useState, type FormEvent, type ReactNode } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Link, useNavigate, useParams, useSearchParams } from 'react-router-dom';
import { ArrowLeft, Download, Plus, Save, Upload } from 'lucide-react';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { ComplianceEmpty, ComplianceError, CompliancePage, ComplianceSkeleton, ComplianceSurface } from '../components/CompliancePageState';
import { ComplianceStatusBadge } from '../components/ComplianceStatusBadge';
import { PolicyForm } from '../components/PolicyForm';
import { EvidenceForm } from '../components/EvidenceForm';
import { ROUTES } from '../contracts';
import type { ComplianceConfigurationDocument, ConfigurationPortableDocument, EvidenceWriteRequest, FrameworkWriteRequest, PolicyWriteRequest, RequirementWriteRequest, RuntimeEnvironment, UUID } from '../contracts';
import { complianceService, createIdempotencyKey } from '../services/compliance-service';

const keys = { root: ['compliance'] as const, frameworks: (filters: object) => ['compliance', 'frameworks', filters] as const, requirements: (filters: object) => ['compliance', 'requirements', filters] as const, policies: (filters: object) => ['compliance', 'policies', filters] as const, evidence: (filters: object) => ['compliance', 'evidence', filters] as const, configuration: (filters: object) => ['compliance', 'configuration', filters] as const };
const date = (value?: string | null) => value ? new Intl.DateTimeFormat(undefined, { dateStyle: 'medium' }).format(new Date(value)) : '—';
const can = (actions: readonly string[] | undefined, action: string) => !actions || actions.includes(action);

function PageActions({ back, children }: { readonly back: string; readonly children?: ReactNode }) { return <><Link to={back}><Button variant="outline"><ArrowLeft className="mr-2 h-4 w-4"/>Back</Button></Link>{children}</>; }
function Pagination({ page, total, previous, next, onChange }: { readonly page: number; readonly total: number; readonly previous: boolean; readonly next: boolean; readonly onChange: (page: number) => void }) { return <nav aria-label="Pagination" className="flex items-center justify-between border-t p-4 text-sm"><span>Page {page} of {Math.max(total, 1)}</span><div className="flex gap-2"><Button size="sm" variant="outline" disabled={!previous} onClick={() => onChange(page - 1)}>Previous</Button><Button size="sm" variant="outline" disabled={!next} onClick={() => onChange(page + 1)}>Next</Button></div></nav>; }
function ListToolbar({ name, params, setParams, children }: { readonly name: string; readonly params: URLSearchParams; readonly setParams: (next: URLSearchParams) => void; readonly children?: ReactNode }) {
  const save = () => localStorage.setItem(`compliance-filter:${name}`, params.toString());
  const restore = () => setParams(new URLSearchParams(localStorage.getItem(`compliance-filter:${name}`) ?? ''));
  return <div className="grid gap-3 rounded-xl border bg-card p-4 md:grid-cols-[minmax(200px,1fr)_auto_auto_auto]"><Input aria-label="Search" placeholder="Search…" defaultValue={params.get('search') ?? ''} onKeyDown={(event) => { if (event.key === 'Enter') { const next = new URLSearchParams(params); next.set('search', event.currentTarget.value); next.set('page', '1'); setParams(next); } }}/>{children}<Button variant="outline" onClick={save}><Save className="mr-2 h-4 w-4"/>Save filter</Button><Button variant="ghost" onClick={restore}>Restore</Button></div>;
}
function SimpleTable({ headings, children }: { readonly headings: readonly string[]; readonly children: ReactNode }) { return <div className="overflow-x-auto rounded-xl border bg-card"><table className="w-full min-w-[720px] text-sm"><thead><tr className="border-b bg-muted/40 text-left text-xs uppercase text-muted-foreground">{headings.map((heading) => <th key={heading} className="p-4">{heading}</th>)}</tr></thead><tbody className="divide-y">{children}</tbody></table></div>; }
function DetailGrid({ children }: { readonly children: ReactNode }) { return <dl className="grid gap-5 sm:grid-cols-2 lg:grid-cols-3">{children}</dl>; }
function Detail({ label, children }: { readonly label: string; readonly children: ReactNode }) { return <div><dt className="text-xs font-medium uppercase text-muted-foreground">{label}</dt><dd className="mt-1 break-words text-sm">{children}</dd></div>; }

export function ComplianceDashboardPage() {
  const query = useQuery({ queryKey: ['compliance', 'dashboard'], queryFn: () => complianceService.dashboard() });
  if (query.isLoading) return <ComplianceSkeleton/>; if (query.error) return <CompliancePage title="Compliance workspace" description="Readiness and work queues"><ComplianceError error={query.error} onRetry={() => void query.refetch()}/></CompliancePage>; if (!query.data) return <CompliancePage title="Compliance workspace" description="Readiness and work queues"><ComplianceError error={new Error('No dashboard response was received.')}/></CompliancePage>;
  const summary = query.data;
  const steps = [
    { title: 'Choose a framework', route: ROUTES.FRAMEWORKS, complete: summary.frameworks > 0 },
    { title: 'Import requirements', route: ROUTES.REQUIREMENTS, complete: summary.requirements > 0 },
    { title: 'Author policies', route: ROUTES.POLICIES, complete: summary.gaps < summary.requirements },
    { title: 'Attach evidence and assess', route: ROUTES.EVIDENCE, complete: summary.unassessed_requirements === 0 },
  ];
  return <CompliancePage title="Compliance workspace" description="A live, explainable view of framework readiness, policy review, evidence freshness, and assessment gaps."><section className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{[['Requirements', summary.requirements], ['Open gaps', summary.gaps], ['Due for review', summary.review_queue], ['Expiring evidence', summary.expiring_evidence]].map(([label, value]) => <div key={label} className="rounded-xl border bg-card p-5"><p className="text-sm text-muted-foreground">{label}</p><p className="mt-2 text-3xl font-bold">{value}</p></div>)}</section><ComplianceSurface title="Guided onboarding"><ol className="grid gap-3 md:grid-cols-2">{steps.map((step) => <li key={step.title}><Link className="flex rounded-lg border p-4 hover:bg-muted/50" to={step.route}><ComplianceStatusBadge status={step.complete ? 'complete' : 'next'}/><span className="ml-3 font-medium">{step.title}</span></Link></li>)}</ol></ComplianceSurface><ComplianceSurface title="Assessment queue">{summary.unassessed_requirements ? <p>{summary.unassessed_requirements} applicable requirements still need an assessment.</p> : <ComplianceEmpty title="Queue is clear" description="No requirements are currently unassessed."/>}</ComplianceSurface></CompliancePage>;
}

export function FrameworkListPage() { const navigate = useNavigate(); const [params, setParams] = useSearchParams(); const filters = { page: Number(params.get('page') ?? 1), page_size: 25, search: params.get('search') ?? undefined, status: (params.get('status') || undefined) as 'draft' | 'active' | 'archived' | undefined, ordering: params.get('ordering') ?? 'name' }; const query = useQuery({ queryKey: keys.frameworks(filters), queryFn: () => complianceService.frameworks.list(filters) }); if (query.isLoading) return <ComplianceSkeleton/>; return <CompliancePage title="Frameworks" description="Adopt custom, imported, or extension-provided compliance frameworks." actions={<Button onClick={() => navigate(ROUTES.FRAMEWORK_CREATE)}><Plus className="mr-2 h-4 w-4"/>New framework</Button>}><ListToolbar name="frameworks" params={params} setParams={setParams}><select aria-label="Framework status" className="rounded-md border bg-background px-3" value={filters.status ?? ''} onChange={(e) => { const n = new URLSearchParams(params); e.target.value ? n.set('status', e.target.value) : n.delete('status'); setParams(n); }}><option value="">All statuses</option><option>draft</option><option>active</option><option>archived</option></select></ListToolbar>{query.error ? <ComplianceError error={query.error} onRetry={() => void query.refetch()}/> : query.data?.data.length ? <><SimpleTable headings={['Code', 'Framework', 'Category', 'Source', 'Status']} >{query.data.data.map((item) => <tr key={item.id} className="hover:bg-muted/30"><td className="p-4 font-mono">{item.code}</td><td className="p-4"><Link className="font-medium hover:underline" to={ROUTES.FRAMEWORK_DETAIL(item.id)}>{item.name}</Link><small className="block text-muted-foreground">Version {item.version}</small></td><td className="p-4">{item.category}</td><td className="p-4">{item.source_kind}</td><td className="p-4"><ComplianceStatusBadge status={item.status}/></td></tr>)}</SimpleTable><Pagination page={query.data.meta.pagination.page} total={query.data.meta.pagination.total_pages} previous={query.data.meta.pagination.has_previous} next={query.data.meta.pagination.has_next} onChange={(page) => { const n = new URLSearchParams(params); n.set('page', String(page)); setParams(n); }}/></> : <ComplianceEmpty title="No frameworks" description="Define a framework to start the manual compliance loop." action={<Button onClick={() => navigate(ROUTES.FRAMEWORK_CREATE)}>Create framework</Button>}/>}</CompliancePage>; }

function FrameworkFormPage({ edit }: { readonly edit: boolean }) { const { id = '' } = useParams(); const navigate = useNavigate(); const cache = useQueryClient(); const existing = useQuery({ queryKey: ['compliance', 'framework', id], queryFn: () => complianceService.frameworks.get(id), enabled: edit && Boolean(id) }); const [form, setForm] = useState<FrameworkWriteRequest>({ code: '', name: '', version: '1.0', category: '', description: '', source_kind: 'custom', source_package: '', source_version: '' }); const value = edit && existing.data ? { code: existing.data.code, name: existing.data.name, version: existing.data.version, category: existing.data.category, description: existing.data.description, source_kind: existing.data.source_kind, source_package: existing.data.source_package, source_version: existing.data.source_version } : form; const mutation = useMutation({ mutationFn: (body: FrameworkWriteRequest) => edit ? complianceService.frameworks.update(id, body) : complianceService.frameworks.create(body), onSuccess: async (record) => { await cache.invalidateQueries({ queryKey: ['compliance', 'frameworks'] }); navigate(ROUTES.FRAMEWORK_DETAIL(record.id), { state: { success: `Framework ${edit ? 'updated' : 'created'}.` } }); } }); if (edit && existing.isLoading) return <ComplianceSkeleton/>; if (existing.error) return <CompliancePage title="Edit framework" description="Update framework metadata"><ComplianceError error={existing.error} onRetry={() => void existing.refetch()}/></CompliancePage>; const submit = (event: FormEvent) => { event.preventDefault(); if (value.code.trim() && value.name.trim() && value.category.trim() && value.version.trim()) mutation.mutate(value); }; const set = (key: keyof FrameworkWriteRequest, next: string) => setForm((current) => ({ ...value, ...current, [key]: next })); return <CompliancePage title={edit ? 'Edit framework' : 'Create framework'} description="Framework categories are validated against the active tenant configuration." actions={<PageActions back={edit ? ROUTES.FRAMEWORK_DETAIL(id) : ROUTES.FRAMEWORKS}/>}><ComplianceSurface><form className="space-y-5" onSubmit={submit}><div className="grid gap-4 sm:grid-cols-2"><Input label="Code" required value={value.code} onChange={(e) => set('code', e.target.value)}/><Input label="Name" required value={value.name} onChange={(e) => set('name', e.target.value)}/><Input label="Version" required value={value.version} onChange={(e) => set('version', e.target.value)}/><Input label="Category" required value={value.category} onChange={(e) => set('category', e.target.value)}/><label className="text-sm font-medium">Source kind<select className="mt-1 block w-full rounded-md border bg-background px-3 py-2" value={value.source_kind} onChange={(e) => set('source_kind', e.target.value)}><option value="custom">Custom</option><option value="imported">Imported</option><option value="extension">Extension</option></select></label>{value.source_kind === 'extension' ? <Input label="Source package" required value={value.source_package ?? ''} onChange={(e) => set('source_package', e.target.value)}/> : null}</div><label className="block text-sm font-medium">Description<textarea className="mt-1 min-h-28 w-full rounded-md border bg-background p-3" value={value.description ?? ''} onChange={(e) => set('description', e.target.value)}/></label>{mutation.error ? <ComplianceError error={mutation.error}/> : null}<Button type="submit" disabled={mutation.isPending}>{mutation.isPending ? 'Saving…' : 'Save framework'}</Button></form></ComplianceSurface></CompliancePage>; }
export function CreateFrameworkPage() { return <FrameworkFormPage edit={false}/>; } export function EditFrameworkPage() { return <FrameworkFormPage edit/>; }

export function FrameworkDetailPage() { const { id = '' } = useParams(); const cache = useQueryClient(); const query = useQuery({ queryKey: ['compliance', 'framework', id], queryFn: () => complianceService.frameworks.get(id), enabled: Boolean(id) }); const status = useQuery({ queryKey: ['compliance', 'framework-status', id], queryFn: () => complianceService.frameworks.status(id), enabled: Boolean(id) }); const activate = useMutation({ mutationFn: () => complianceService.frameworks.activate(id, { transition_key: createIdempotencyKey('activate-framework') }), onSuccess: async () => { await query.refetch(); await cache.invalidateQueries({ queryKey: ['compliance', 'frameworks'] }); } }); if (query.isLoading) return <ComplianceSkeleton/>; if (query.error) return <CompliancePage title="Framework" description="Framework details"><ComplianceError error={query.error} onRetry={() => void query.refetch()}/></CompliancePage>; if (!query.data) return <CompliancePage title="Framework" description="Framework details"><ComplianceError error={new Error('Framework not found.')}/></CompliancePage>; const item = query.data; return <CompliancePage title={item.name} description={`${item.code} · version ${item.version}`} actions={<PageActions back={ROUTES.FRAMEWORKS}>{can(item.allowed_actions, 'update') ? <Link to={ROUTES.FRAMEWORK_EDIT(item.id)}><Button variant="outline">Edit</Button></Link> : null}{item.status === 'draft' && can(item.allowed_actions, 'activate') ? <Button disabled={activate.isPending} onClick={() => activate.mutate()}>{activate.isPending ? 'Activating…' : 'Activate'}</Button> : null}</PageActions>}><ComplianceSurface title="Framework metadata"><DetailGrid><Detail label="Status"><ComplianceStatusBadge status={item.status}/></Detail><Detail label="Category">{item.category}</Detail><Detail label="Source">{item.source_kind}</Detail><Detail label="Requirements">{item.requirement_count ?? status.data?.framework.requirement_count ?? '—'}</Detail><Detail label="Updated">{date(item.updated_at)}</Detail></DetailGrid><p className="mt-5 text-sm text-muted-foreground">{item.description || 'No description provided.'}</p></ComplianceSurface>{status.data ? <ComplianceSurface title="Readiness snapshot"><DetailGrid><Detail label="Readiness">{status.data.readiness.score.toFixed(1)}%</Detail><Detail label="Mapped">{status.data.gaps.total - status.data.gaps.gap_count}</Detail><Detail label="Assessed">{status.data.readiness.requirements.filter((entry) => entry.status !== 'not_assessed').length}</Detail><Detail label="Fresh evidence">{'See evidence workspace'}</Detail></DetailGrid></ComplianceSurface> : status.error ? <ComplianceError error={status.error} onRetry={() => void status.refetch()}/> : null}{activate.error ? <ComplianceError error={activate.error}/> : null}</CompliancePage>; }

export function RequirementListPage() { const navigate = useNavigate(); const [params, setParams] = useSearchParams(); const filters = { page: Number(params.get('page') ?? 1), page_size: 25, search: params.get('search') ?? undefined, framework_id: params.get('framework_id') ?? undefined, ordering: params.get('ordering') ?? 'sort_order' }; const query = useQuery({ queryKey: keys.requirements(filters), queryFn: () => complianceService.requirements.list(filters) }); if (query.isLoading) return <ComplianceSkeleton/>; return <CompliancePage title="Requirements" description="Normative framework requirements, applicability, mappings, evidence, and assessment state." actions={<Button onClick={() => navigate(ROUTES.REQUIREMENT_CREATE)}><Plus className="mr-2 h-4 w-4"/>New requirement</Button>}><ListToolbar name="requirements" params={params} setParams={setParams}><Input aria-label="Framework UUID" placeholder="Framework UUID" defaultValue={filters.framework_id} onBlur={(e) => { const n = new URLSearchParams(params); e.target.value ? n.set('framework_id', e.target.value) : n.delete('framework_id'); setParams(n); }}/></ListToolbar>{query.error ? <ComplianceError error={query.error} onRetry={() => void query.refetch()}/> : query.data?.data.length ? <><SimpleTable headings={['Code', 'Requirement', 'Framework', 'Applicability', 'Coverage']} >{query.data.data.map((item) => <tr key={item.id}><td className="p-4 font-mono">{item.code}</td><td className="p-4"><Link className="font-medium hover:underline" to={ROUTES.REQUIREMENT_DETAIL(item.id)}>{item.title}</Link><small className="block text-muted-foreground">{item.section}</small></td><td className="p-4">{item.framework_code ?? item.framework}</td><td className="p-4"><ComplianceStatusBadge status={item.applicability}/></td><td className="p-4">{item.mapping_count ?? 0} policies · {item.evidence_count ?? 0} evidence</td></tr>)}</SimpleTable><Pagination page={query.data.meta.pagination.page} total={query.data.meta.pagination.total_pages} previous={query.data.meta.pagination.has_previous} next={query.data.meta.pagination.has_next} onChange={(page) => { const n = new URLSearchParams(params); n.set('page', String(page)); setParams(n); }}/></> : <ComplianceEmpty title="No requirements" description="Add requirements after defining a framework." action={<Button onClick={() => navigate(ROUTES.REQUIREMENT_CREATE)}>Create requirement</Button>}/>}</CompliancePage>; }

function RequirementFormPage({ edit }: { readonly edit: boolean }) { const { id = '' } = useParams(); const navigate = useNavigate(); const cache = useQueryClient(); const existing = useQuery({ queryKey: ['compliance', 'requirement', id], queryFn: () => complianceService.requirements.get(id), enabled: edit && Boolean(id) }); const [value, setValue] = useState<RequirementWriteRequest>({ framework_id: '', code: '', title: '', description: '', section: '', guidance: '', applicability: 'applicable', applicability_rationale: '', sort_order: 0, tags: [] }); const current = edit && existing.data ? { framework_id: existing.data.framework, code: existing.data.code, title: existing.data.title, description: existing.data.description, section: existing.data.section, guidance: existing.data.guidance, applicability: existing.data.applicability, applicability_rationale: existing.data.applicability_rationale, sort_order: existing.data.sort_order, tags: existing.data.tags } : value; const mutation = useMutation({ mutationFn: (body: RequirementWriteRequest) => edit ? complianceService.requirements.update(id, body) : complianceService.requirements.create(body), onSuccess: async (record) => { await cache.invalidateQueries({ queryKey: ['compliance', 'requirements'] }); navigate(ROUTES.REQUIREMENT_DETAIL(record.id)); } }); if (edit && existing.isLoading) return <ComplianceSkeleton/>; if (existing.error) return <CompliancePage title="Edit requirement" description="Requirement details"><ComplianceError error={existing.error}/></CompliancePage>; const set = <K extends keyof RequirementWriteRequest>(key: K, next: RequirementWriteRequest[K]) => setValue((prior) => ({ ...current, ...prior, [key]: next })); return <CompliancePage title={edit ? 'Edit requirement' : 'Create requirement'} description="Applicability and tags are validated server-side against active configuration." actions={<PageActions back={edit ? ROUTES.REQUIREMENT_DETAIL(id) : ROUTES.REQUIREMENTS}/>}><ComplianceSurface><form className="space-y-5" onSubmit={(event) => { event.preventDefault(); if (current.framework_id && current.code.trim() && current.title.trim() && current.description.trim()) mutation.mutate(current); }}><div className="grid gap-4 sm:grid-cols-2"><Input label="Framework UUID" required value={current.framework_id} disabled={edit} onChange={(e) => set('framework_id', e.target.value)}/><Input label="Code" required value={current.code} onChange={(e) => set('code', e.target.value)}/><Input label="Title" required value={current.title} onChange={(e) => set('title', e.target.value)}/><Input label="Section" value={current.section ?? ''} onChange={(e) => set('section', e.target.value)}/><Input label="Sort order" type="number" min={0} value={current.sort_order ?? 0} onChange={(e) => set('sort_order', Number(e.target.value))}/><label className="text-sm font-medium">Applicability<select className="mt-1 block w-full rounded-md border bg-background px-3 py-2" value={current.applicability} onChange={(e) => set('applicability', e.target.value as 'applicable' | 'not_applicable')}><option value="applicable">Applicable</option><option value="not_applicable">Not applicable</option></select></label>{current.applicability === 'not_applicable' ? <Input label="Applicability rationale" required value={current.applicability_rationale ?? ''} onChange={(e) => set('applicability_rationale', e.target.value)}/> : null}<Input label="Tags (comma separated, max 50)" value={current.tags?.join(', ') ?? ''} onChange={(e) => set('tags', [...new Set(e.target.value.split(',').map((tag) => tag.trim()).filter(Boolean))].slice(0, 50))}/></div><label className="block text-sm font-medium">Description<textarea required className="mt-1 min-h-28 w-full rounded-md border bg-background p-3" value={current.description} onChange={(e) => set('description', e.target.value)}/></label><label className="block text-sm font-medium">Guidance<textarea className="mt-1 min-h-24 w-full rounded-md border bg-background p-3" value={current.guidance ?? ''} onChange={(e) => set('guidance', e.target.value)}/></label>{mutation.error ? <ComplianceError error={mutation.error}/> : null}<Button disabled={mutation.isPending}>{mutation.isPending ? 'Saving…' : 'Save requirement'}</Button></form></ComplianceSurface></CompliancePage>; }
export function CreateRequirementPage() { return <RequirementFormPage edit={false}/>; } export function EditRequirementPage() { return <RequirementFormPage edit/>; }

export function RequirementDetailPage() { const { id = '' } = useParams(); const query = useQuery({ queryKey: ['compliance', 'requirement', id], queryFn: () => complianceService.requirements.get(id), enabled: Boolean(id) }); const assessments = useQuery({ queryKey: ['compliance', 'assessments', id], queryFn: () => complianceService.assessments.list({ requirement_id: id, ordering: '-assessed_at' }), enabled: Boolean(id) }); const mappings = useQuery({ queryKey: ['compliance', 'mappings', id], queryFn: () => complianceService.mappings.list({ requirement_id: id }), enabled: Boolean(id) }); const evidence = useQuery({ queryKey: ['compliance', 'evidence', id], queryFn: () => complianceService.evidence.list({ requirement_id: id }), enabled: Boolean(id) }); if (query.isLoading) return <ComplianceSkeleton/>; if (query.error) return <CompliancePage title="Requirement" description="Requirement details"><ComplianceError error={query.error} onRetry={() => void query.refetch()}/></CompliancePage>; if (!query.data) return <CompliancePage title="Requirement" description="Requirement details"><ComplianceError error={new Error('Requirement not found.')}/></CompliancePage>; const item = query.data; return <CompliancePage title={item.title} description={`${item.code} · ${item.framework_code ?? item.framework}`} actions={<PageActions back={ROUTES.REQUIREMENTS}>{can(item.allowed_actions, 'update') ? <Link to={ROUTES.REQUIREMENT_EDIT(item.id)}><Button variant="outline">Edit</Button></Link> : null}<Link to={`${ROUTES.ASSESSMENT_CREATE}?requirement=${item.id}`}><Button>Assess</Button></Link></PageActions>}><ComplianceSurface title="Requirement"><DetailGrid><Detail label="Status"><ComplianceStatusBadge status={item.status}/></Detail><Detail label="Applicability"><ComplianceStatusBadge status={item.applicability}/></Detail><Detail label="Gap status">{item.gap_status ?? (item.mapping_count ? 'mapped' : 'unmapped')}</Detail><Detail label="Section">{item.section || '—'}</Detail><Detail label="Tags">{item.tags.join(', ') || '—'}</Detail><Detail label="Updated">{date(item.updated_at)}</Detail></DetailGrid><p className="mt-5 whitespace-pre-wrap text-sm">{item.description}</p></ComplianceSurface><section className="grid gap-5 xl:grid-cols-3"><ComplianceSurface title="Latest assessment">{assessments.data?.data[0] ? <><ComplianceStatusBadge status={assessments.data.data[0].status}/><p className="mt-3 text-sm">{assessments.data.data[0].notes || 'No notes.'}</p><Link className="mt-3 inline-block text-sm underline" to={`${ROUTES.ASSESSMENTS}?requirement_id=${id}`}>Full history</Link></> : <ComplianceEmpty title="Unassessed" description="Record the first point-in-time assessment."/>}</ComplianceSurface><ComplianceSurface title="Policy mappings">{mappings.data?.data.length ? <ul>{mappings.data.data.map((mapping) => <li key={mapping.id} className="py-2">{mapping.policy_code ?? mapping.policy} · {mapping.coverage}</li>)}</ul> : <p className="text-sm text-muted-foreground">This requirement is an explainable gap because no policy maps to it.</p>}</ComplianceSurface><ComplianceSurface title="Evidence">{evidence.data?.data.length ? <ul>{evidence.data.data.map((item) => <li key={item.id} className="py-2"><Link className="hover:underline" to={ROUTES.EVIDENCE_DETAIL(item.id)}>{item.name}</Link></li>)}</ul> : <p className="text-sm text-muted-foreground">No evidence is attached.</p>}</ComplianceSurface></section></CompliancePage>; }

export function CompliancePolicyListPage() { const navigate = useNavigate(); const [params, setParams] = useSearchParams(); const filters = { page: Number(params.get('page') ?? 1), page_size: 25, search: params.get('search') ?? undefined, status: (params.get('status') || undefined) as 'draft' | 'in_review' | 'approved' | 'published' | 'archived' | undefined, ordering: params.get('ordering') ?? 'title' }; const query = useQuery({ queryKey: keys.policies(filters), queryFn: () => complianceService.policies.list(filters) }); if (query.isLoading) return <ComplianceSkeleton/>; return <CompliancePage title="Policies" description="Author, review, approve, publish, and revise immutable policy versions." actions={<Button onClick={() => navigate(ROUTES.POLICY_CREATE)}><Plus className="mr-2 h-4 w-4"/>New policy</Button>}><ListToolbar name="policies" params={params} setParams={setParams}><select aria-label="Policy status" className="rounded-md border bg-background px-3" value={filters.status ?? ''} onChange={(e) => { const n = new URLSearchParams(params); e.target.value ? n.set('status', e.target.value) : n.delete('status'); setParams(n); }}><option value="">All statuses</option>{['draft','in_review','approved','published','archived'].map((status) => <option key={status}>{status}</option>)}</select></ListToolbar>{query.error ? <ComplianceError error={query.error} onRetry={() => void query.refetch()}/> : query.data?.data.length ? <><SimpleTable headings={['Code', 'Policy', 'Owner', 'Review due', 'Status']} >{query.data.data.map((item) => <tr key={item.id}><td className="p-4 font-mono">{item.code}</td><td className="p-4"><Link className="font-medium hover:underline" to={ROUTES.POLICY_DETAIL(item.id)}>{item.title}</Link><small className="block text-muted-foreground">Version {item.current_version}</small></td><td className="p-4">{item.owner_name ?? item.owner ?? 'Unassigned'}</td><td className="p-4">{date(item.next_review_date)}</td><td className="p-4"><ComplianceStatusBadge status={item.status}/></td></tr>)}</SimpleTable><Pagination page={query.data.meta.pagination.page} total={query.data.meta.pagination.total_pages} previous={query.data.meta.pagination.has_previous} next={query.data.meta.pagination.has_next} onChange={(page) => { const n = new URLSearchParams(params); n.set('page', String(page)); setParams(n); }}/></> : <ComplianceEmpty title="No policies" description="Create policy metadata, then author its first immutable version." action={<Button onClick={() => navigate(ROUTES.POLICY_CREATE)}>Create policy</Button>}/>}</CompliancePage>; }

function PolicyFormPage({ edit }: { readonly edit: boolean }) { const { id = '' } = useParams(); const navigate = useNavigate(); const cache = useQueryClient(); const existing = useQuery({ queryKey: ['compliance', 'policy', id], queryFn: () => complianceService.policies.get(id), enabled: edit && Boolean(id) }); const mutation = useMutation({ mutationFn: (body: PolicyWriteRequest) => edit ? complianceService.policies.update(id, body) : complianceService.policies.create(body), onSuccess: async (record) => { await cache.invalidateQueries({ queryKey: ['compliance', 'policies'] }); navigate(ROUTES.POLICY_DETAIL(record.id)); } }); if (edit && existing.isLoading) return <ComplianceSkeleton/>; if (existing.error) return <CompliancePage title="Edit policy" description="Policy metadata"><ComplianceError error={existing.error}/></CompliancePage>; const initial = existing.data ? { code: existing.data.code, title: existing.data.title, summary: existing.data.summary, category: existing.data.category, owner: existing.data.owner, review_frequency_days: existing.data.review_frequency_days, effective_date: existing.data.effective_date, expiry_date: existing.data.expiry_date, next_review_date: existing.data.next_review_date } : undefined; return <CompliancePage title={edit ? 'Edit policy' : 'Create policy'} description="Lifecycle status is controlled only through explicit governed actions." actions={<PageActions back={edit ? ROUTES.POLICY_DETAIL(id) : ROUTES.POLICIES}/>}><ComplianceSurface><PolicyForm initial={initial} pending={mutation.isPending} error={mutation.error} submitLabel="Save policy" onSubmit={(body) => mutation.mutate(body)} onCancel={() => navigate(edit ? ROUTES.POLICY_DETAIL(id) : ROUTES.POLICIES)}/>{mutation.error ? <div className="mt-4"><ComplianceError error={mutation.error}/></div> : null}</ComplianceSurface></CompliancePage>; }
export function CreateCompliancePolicyPage() { return <PolicyFormPage edit={false}/>; } export function EditCompliancePolicyPage() { return <PolicyFormPage edit/>; }

export function CompliancePolicyDetailPage() { const { id = '' } = useParams(); const cache = useQueryClient(); const query = useQuery({ queryKey: ['compliance', 'policy', id], queryFn: () => complianceService.policies.get(id), enabled: Boolean(id) }); const versions = useQuery({ queryKey: ['compliance', 'policy-versions', id], queryFn: () => complianceService.policies.versions(id), enabled: Boolean(id) }); const mappings = useQuery({ queryKey: ['compliance', 'policy-mappings', id], queryFn: () => complianceService.mappings.list({ policy_id: id }), enabled: Boolean(id) }); const activity = useQuery({ queryKey: ['compliance', 'policy-activity', id], queryFn: () => complianceService.activity({ entity_type: 'policy', entity_id: id, page_size: 10 }), enabled: Boolean(id) }); const [content, setContent] = useState(''); const [summary, setSummary] = useState(''); const createVersion = useMutation({ mutationFn: () => complianceService.policies.createVersion(id, { content, change_summary: summary }, createIdempotencyKey('policy-version')), onSuccess: async () => { setContent(''); setSummary(''); await versions.refetch(); await query.refetch(); } }); const transition = useMutation({ mutationFn: (action: 'submit' | 'request-changes' | 'approve' | 'publish') => complianceService.policies.transition(id, action, { transition_key: createIdempotencyKey(`policy-${action}`), reason: action === 'request-changes' ? 'Changes requested by reviewer' : undefined }), onSuccess: async () => { await query.refetch(); await cache.invalidateQueries({ queryKey: ['compliance', 'policies'] }); } }); if (query.isLoading) return <ComplianceSkeleton/>; if (query.error) return <CompliancePage title="Policy" description="Policy details"><ComplianceError error={query.error} onRetry={() => void query.refetch()}/></CompliancePage>; if (!query.data) return <CompliancePage title="Policy" description="Policy details"><ComplianceError error={new Error('Policy not found.')}/></CompliancePage>; const item = query.data; const actions: Record<string, readonly ('submit'|'request-changes'|'approve'|'publish')[]> = { draft: ['submit'], in_review: ['request-changes','approve'], approved: ['publish'] }; return <CompliancePage title={item.title} description={`${item.code} · immutable version ${item.current_version}`} actions={<PageActions back={ROUTES.POLICIES}>{can(item.allowed_actions, 'update') && item.status === 'draft' ? <Link to={ROUTES.POLICY_EDIT(item.id)}><Button variant="outline">Edit metadata</Button></Link> : null}{(actions[item.status] ?? []).filter((action) => can(item.allowed_actions, action)).map((action) => <Button key={action} disabled={transition.isPending} onClick={() => transition.mutate(action)}>{transition.isPending ? 'Working…' : action.replaceAll('-', ' ')}</Button>)}</PageActions>}><ComplianceSurface title="Lifecycle and review"><DetailGrid><Detail label="Status"><ComplianceStatusBadge status={item.status}/></Detail><Detail label="Owner">{item.owner_name ?? item.owner ?? 'Unassigned'}</Detail><Detail label="Category">{item.category}</Detail><Detail label="Effective">{date(item.effective_date)}</Detail><Detail label="Expires">{date(item.expiry_date)}</Detail><Detail label="Next review">{date(item.next_review_date)}</Detail><Detail label="Requirement coverage">{item.mapping_count ?? mappings.data?.data.length ?? 0}</Detail></DetailGrid><p className="mt-5 text-sm">{item.summary || 'No summary provided.'}</p></ComplianceSurface>{item.status === 'draft' ? <ComplianceSurface title="Author immutable version"><form className="space-y-4" onSubmit={(e) => { e.preventDefault(); if (content.trim() && summary.trim()) createVersion.mutate(); }}><label className="block text-sm font-medium">Policy content<textarea required className="mt-1 min-h-48 w-full rounded-md border bg-background p-3 font-mono text-sm" value={content} onChange={(e) => setContent(e.target.value)}/></label><Input label="Change summary" required value={summary} onChange={(e) => setSummary(e.target.value)}/><Button disabled={createVersion.isPending}>{createVersion.isPending ? 'Creating version…' : 'Create immutable version'}</Button></form></ComplianceSurface> : null}<ComplianceSurface title="Version history">{versions.error ? <ComplianceError error={versions.error} onRetry={() => void versions.refetch()}/> : versions.data?.data.length ? <ol className="divide-y">{versions.data.data.map((version) => <li key={version.id} className="py-4"><div className="flex justify-between"><strong>Version {version.version}</strong><time className="text-sm text-muted-foreground">{date(version.created_at)}</time></div><p className="mt-1 text-sm">{version.change_summary}</p><details className="mt-2"><summary className="cursor-pointer text-sm underline">Review content</summary><pre className="mt-2 whitespace-pre-wrap rounded bg-muted p-4 text-sm">{version.content}</pre></details></li>)}</ol> : <ComplianceEmpty title="No policy versions" description="Author an immutable version before submitting this policy."/>}</ComplianceSurface><section className="grid gap-5 lg:grid-cols-2"><ComplianceSurface title="Requirement coverage">{mappings.data?.data.length ? <ul>{mappings.data.data.map((mapping) => <li key={mapping.id} className="py-2">{mapping.requirement_code ?? mapping.requirement} · {mapping.coverage}</li>)}</ul> : <p className="text-sm text-muted-foreground">This policy is not mapped to requirements.</p>}</ComplianceSurface><ComplianceSurface title="Recent activity">{activity.data?.data.length ? <ol>{activity.data.data.map((entry) => <li key={entry.id} className="border-b py-2 text-sm">{entry.action}<small className="block text-muted-foreground">{date(entry.occurred_at)} · {entry.correlation_id}</small></li>)}</ol> : <p className="text-sm text-muted-foreground">No activity was recorded.</p>}</ComplianceSurface></section>{transition.error ? <ComplianceError error={transition.error}/> : null}{createVersion.error ? <ComplianceError error={createVersion.error}/> : null}</CompliancePage>; }

export function RequirementMappingPage() { const [params] = useSearchParams(); const frameworkId = params.get('framework_id') ?? ''; const [rows, setRows] = useState<Record<UUID, { policy: UUID; coverage: 'full' | 'partial' }>>({}); const requirements = useQuery({ queryKey: ['compliance', 'mapping-requirements', frameworkId], queryFn: () => complianceService.requirements.list({ framework_id: frameworkId, page_size: 100 }), enabled: Boolean(frameworkId) }); const policies = useQuery({ queryKey: ['compliance', 'mapping-policies'], queryFn: () => complianceService.policies.list({ page_size: 100, status: 'published' }) }); const mutation = useMutation({ mutationFn: () => complianceService.mappings.bulk({ rows: Object.entries(rows).filter(([, row]) => row.policy).map(([requirement_id, row]) => ({ requirement_id, policy_id: row.policy, coverage: row.coverage })) }, createIdempotencyKey('bulk-mapping')), onSuccess: () => setRows({}) }); return <CompliancePage title="Requirement mapping" description="Map requirements to published policies and record full or partial coverage inline." actions={<PageActions back={ROUTES.REQUIREMENTS}/>}><ComplianceSurface><Input label="Framework UUID" value={frameworkId} readOnly={Boolean(frameworkId)} placeholder="Open this workspace with ?framework_id=…"/></ComplianceSurface>{requirements.isLoading || policies.isLoading ? <ComplianceSkeleton rows={4}/> : requirements.error || policies.error ? <ComplianceError error={(requirements.error ?? policies.error) as Error} onRetry={() => { void requirements.refetch(); void policies.refetch(); }}/> : requirements.data?.data.length ? <ComplianceSurface><div className="space-y-3">{requirements.data.data.map((requirement) => <div key={requirement.id} className="grid gap-3 rounded-lg border p-4 md:grid-cols-[1fr_280px_140px]"><span><strong>{requirement.code}</strong><small className="block text-muted-foreground">{requirement.title}</small></span><select aria-label={`Policy for ${requirement.code}`} className="rounded-md border bg-background px-3" value={rows[requirement.id]?.policy ?? ''} onChange={(e) => setRows((current) => ({ ...current, [requirement.id]: { policy: e.target.value, coverage: current[requirement.id]?.coverage ?? 'full' } }))}><option value="">Unmapped</option>{policies.data?.data.map((policy) => <option key={policy.id} value={policy.id}>{policy.code} — {policy.title}</option>)}</select><select aria-label={`Coverage for ${requirement.code}`} className="rounded-md border bg-background px-3" value={rows[requirement.id]?.coverage ?? 'full'} onChange={(e) => setRows((current) => ({ ...current, [requirement.id]: { policy: current[requirement.id]?.policy ?? '', coverage: e.target.value as 'full'|'partial' } }))}><option value="full">Full</option><option value="partial">Partial</option></select></div>)}</div><Button className="mt-5" disabled={mutation.isPending || !Object.values(rows).some((row) => row.policy)} onClick={() => mutation.mutate()}>{mutation.isPending ? 'Saving mappings…' : 'Save coverage updates'}</Button></ComplianceSurface> : <ComplianceEmpty title="No requirements" description="Select a framework with requirements to map policies."/>}{mutation.error ? <ComplianceError error={mutation.error}/> : null}</CompliancePage>; }

export function AssessmentHistoryPage() { const [params, setParams] = useSearchParams(); const filters = { page: Number(params.get('page') ?? 1), page_size: 25, requirement_id: params.get('requirement_id') ?? undefined, status: (params.get('status') || undefined) as 'compliant'|'partial'|'non_compliant'|'not_assessed'|undefined, ordering: '-assessed_at' }; const query = useQuery({ queryKey: ['compliance', 'assessments', filters], queryFn: () => complianceService.assessments.list(filters) }); if (query.isLoading) return <ComplianceSkeleton/>; return <CompliancePage title="Assessment history" description="Immutable, point-in-time compliance assessments." actions={<Link to={ROUTES.ASSESSMENT_CREATE}><Button><Plus className="mr-2 h-4 w-4"/>Record assessment</Button></Link>}><ListToolbar name="assessments" params={params} setParams={setParams}/>{query.error ? <ComplianceError error={query.error} onRetry={() => void query.refetch()}/> : query.data?.data.length ? <SimpleTable headings={['Requirement', 'Status', 'Assessed', 'Due', 'Notes']}>{query.data.data.map((item) => <tr key={item.id}><td className="p-4 font-mono">{item.requirement_code ?? item.requirement}</td><td className="p-4"><ComplianceStatusBadge status={item.status}/></td><td className="p-4">{date(item.assessed_at)}</td><td className="p-4">{date(item.due_date)}</td><td className="max-w-md p-4">{item.notes || '—'}</td></tr>)}</SimpleTable> : <ComplianceEmpty title="No assessments" description="Record an assessment to establish compliance state." action={<Link to={ROUTES.ASSESSMENT_CREATE}><Button>Record assessment</Button></Link>}/>}</CompliancePage>; }

export function CreateAssessmentPage() { const navigate = useNavigate(); const [params] = useSearchParams(); const [requirement, setRequirement] = useState(params.get('requirement') ?? ''); const [status, setStatus] = useState<'compliant'|'partial'|'non_compliant'|'not_assessed'>('compliant'); const [notes, setNotes] = useState(''); const [dueDate, setDueDate] = useState(''); const mutation = useMutation({ mutationFn: () => complianceService.assessments.create({ requirement_id: requirement, status, notes, due_date: dueDate || null }, createIdempotencyKey('assessment')), onSuccess: () => navigate(`${ROUTES.ASSESSMENTS}?requirement_id=${requirement}`) }); return <CompliancePage title="Record assessment" description="Capture an immutable point-in-time decision with supporting rationale." actions={<PageActions back={ROUTES.ASSESSMENTS}/>}><ComplianceSurface><form className="space-y-5" onSubmit={(e) => { e.preventDefault(); if (requirement && (status === 'compliant' || notes.trim())) mutation.mutate(); }}><Input label="Requirement UUID" required value={requirement} onChange={(e) => setRequirement(e.target.value)}/><label className="block text-sm font-medium">Assessment status<select className="mt-1 block w-full rounded-md border bg-background px-3 py-2" value={status} onChange={(e) => setStatus(e.target.value as typeof status)}><option value="compliant">Compliant</option><option value="partial">Partially compliant</option><option value="non_compliant">Non-compliant</option><option value="not_assessed">Not assessed</option></select></label><label className="block text-sm font-medium">Notes {status !== 'compliant' ? '(required)' : ''}<textarea className="mt-1 min-h-28 w-full rounded-md border bg-background p-3" required={status !== 'compliant'} value={notes} onChange={(e) => setNotes(e.target.value)}/></label><Input label="Follow-up due date" type="date" value={dueDate} onChange={(e) => setDueDate(e.target.value)}/>{mutation.error ? <ComplianceError error={mutation.error}/> : null}<Button disabled={mutation.isPending}>{mutation.isPending ? 'Recording…' : 'Record immutable assessment'}</Button></form></ComplianceSurface></CompliancePage>; }

export function EvidenceListPage() { const navigate = useNavigate(); const [params, setParams] = useSearchParams(); const filters = { page: Number(params.get('page') ?? 1), page_size: 25, search: params.get('search') ?? undefined, type: (params.get('type') || undefined) as EvidenceWriteRequest['evidence_type'] | undefined, ordering: '-collected_at' }; const query = useQuery({ queryKey: keys.evidence(filters), queryFn: () => complianceService.evidence.list(filters) }); if (query.isLoading) return <ComplianceSkeleton/>; return <CompliancePage title="Evidence" description="Register, validate, link, and track evidence freshness without exposing sensitive content." actions={<Button onClick={() => navigate(ROUTES.EVIDENCE_CREATE)}><Plus className="mr-2 h-4 w-4"/>Register evidence</Button>}><ListToolbar name="evidence" params={params} setParams={setParams}/>{query.error ? <ComplianceError error={query.error} onRetry={() => void query.refetch()}/> : query.data?.data.length ? <SimpleTable headings={['Evidence', 'Type', 'Classification', 'Collected', 'Freshness']}>{query.data.data.map((item) => <tr key={item.id}><td className="p-4"><Link className="font-medium hover:underline" to={ROUTES.EVIDENCE_DETAIL(item.id)}>{item.name}</Link></td><td className="p-4">{item.evidence_type}</td><td className="p-4">{item.classification}</td><td className="p-4">{date(item.collected_at)}</td><td className="p-4"><ComplianceStatusBadge status={item.valid_until && item.valid_until < new Date().toISOString() ? 'expired' : 'fresh'}/></td></tr>)}</SimpleTable> : <ComplianceEmpty title="No evidence" description="Register a document, link, attestation, or other evidence source." action={<Button onClick={() => navigate(ROUTES.EVIDENCE_CREATE)}>Register evidence</Button>}/>}</CompliancePage>; }

function EvidenceFormPage({ edit }: { readonly edit: boolean }) { const { id = '' } = useParams(); const navigate = useNavigate(); const cache = useQueryClient(); const existing = useQuery({ queryKey: ['compliance', 'evidence-item', id], queryFn: () => complianceService.evidence.get(id), enabled: edit && Boolean(id) }); const mutation = useMutation({ mutationFn: (body: EvidenceWriteRequest) => edit ? complianceService.evidence.update(id, body) : complianceService.evidence.create(body), onSuccess: async (record) => { await cache.invalidateQueries({ queryKey: ['compliance', 'evidence'] }); navigate(ROUTES.EVIDENCE_DETAIL(record.id)); } }); if (edit && existing.isLoading) return <ComplianceSkeleton/>; if (existing.error) return <CompliancePage title="Edit evidence" description="Evidence metadata"><ComplianceError error={existing.error}/></CompliancePage>; const initial = existing.data ? { name: existing.data.name, description: existing.data.description, evidence_type: existing.data.evidence_type, reference_kind: existing.data.reference_kind, classification: existing.data.classification, external_uri: existing.data.external_uri, text_reference: existing.data.text_reference, collection_method: existing.data.collection_method, document_id: existing.data.document_id, sha256: existing.data.sha256, collected_at: existing.data.collected_at, valid_from: existing.data.valid_from, valid_until: existing.data.valid_until } : undefined; return <CompliancePage title={edit ? 'Edit evidence' : 'Register evidence'} description="External sources are accepted only when active configuration allows their host." actions={<PageActions back={edit ? ROUTES.EVIDENCE_DETAIL(id) : ROUTES.EVIDENCE}/>}><ComplianceSurface><EvidenceForm initial={initial} pending={mutation.isPending} error={mutation.error} submitLabel="Save evidence" onSubmit={(body) => mutation.mutate(body)} onCancel={() => navigate(edit ? ROUTES.EVIDENCE_DETAIL(id) : ROUTES.EVIDENCE)}/>{mutation.error ? <div className="mt-4"><ComplianceError error={mutation.error}/></div> : null}</ComplianceSurface></CompliancePage>; }
export function CreateEvidencePage() { return <EvidenceFormPage edit={false}/>; } export function EditEvidencePage() { return <EvidenceFormPage edit/>; }

export function EvidenceDetailPage() { const { id = '' } = useParams(); const query = useQuery({ queryKey: ['compliance', 'evidence-item', id], queryFn: () => complianceService.evidence.get(id), enabled: Boolean(id) }); const validation = useMutation({ mutationFn: () => complianceService.evidence.validate(id) }); if (query.isLoading) return <ComplianceSkeleton/>; if (query.error) return <CompliancePage title="Evidence" description="Evidence details"><ComplianceError error={query.error} onRetry={() => void query.refetch()}/></CompliancePage>; if (!query.data) return <CompliancePage title="Evidence" description="Evidence details"><ComplianceError error={new Error('Evidence not found.')}/></CompliancePage>; const item = query.data; return <CompliancePage title={item.name} description="Evidence provenance, validity, validation, and requirement links." actions={<PageActions back={ROUTES.EVIDENCE}>{can(item.allowed_actions, 'update') ? <Link to={ROUTES.EVIDENCE_EDIT(item.id)}><Button variant="outline">Edit</Button></Link> : null}{can(item.allowed_actions, 'validate') ? <Button disabled={validation.isPending} onClick={() => validation.mutate()}>{validation.isPending ? 'Validating…' : 'Validate now'}</Button> : null}</PageActions>}><ComplianceSurface><DetailGrid><Detail label="Reference">{item.reference_kind}</Detail><Detail label="Type">{item.evidence_type}</Detail><Detail label="Classification">{item.classification}</Detail><Detail label="Collected">{date(item.collected_at)}</Detail><Detail label="Valid from">{date(item.valid_from)}</Detail><Detail label="Valid until">{date(item.valid_until)}</Detail><Detail label="Content SHA-256"><span className="font-mono text-xs">{item.sha256 || 'Not supplied'}</span></Detail></DetailGrid><p className="mt-5 text-sm">{item.description || 'No description.'}</p></ComplianceSurface>{validation.data ? <ComplianceSurface title="Validation result"><DetailGrid><Detail label="Reference">{validation.data.reference_valid ? 'Valid' : 'Invalid'}</Detail><Detail label="Hash">{validation.data.hash_valid ? 'Verified' : 'Mismatch'}</Detail><Detail label="Freshness">{validation.data.fresh ? 'Fresh' : 'Expired or stale'}</Detail><Detail label="Checked">{date(validation.data.checked_at)}</Detail></DetailGrid></ComplianceSurface> : null}{validation.error ? <ComplianceError error={validation.error}/> : null}<ComplianceSurface title="Linked requirements">{item.requirement_links?.length ? <ul>{item.requirement_links.map((link) => <li key={link.id} className="py-2">{link.requirement_code ?? link.requirement} · {link.relevance}</li>)}</ul> : <ComplianceEmpty title="No links" description="Link this evidence from a requirement workflow."/>}</ComplianceSurface></CompliancePage>; }

const defaultDocument: ComplianceConfigurationDocument = { policy_code_prefix: 'POL', default_review_frequency_days: 365, expiry_warning_days: 30, evidence_warning_days: 30, minimum_assessment_note_length: 10, allow_external_evidence_urls: false, bulk_import_row_limit: 1000, regulation_categories: ['General', 'GDPR', 'SOX', 'HIPAA', 'ISO 27001'], rollout: { frameworks: { enabled: true, roles: [], cohorts: [] } } };
export function ConfigurationListPage() { const navigate = useNavigate(); const [params, setParams] = useSearchParams(); const environment = (params.get('environment') ?? 'production') as RuntimeEnvironment; const query = useQuery({ queryKey: keys.configuration({ environment }), queryFn: () => complianceService.configuration.list({ environment, ordering: '-version' }) }); const file = useMemo(() => ({ current: null as HTMLInputElement | null }), []); const importMutation = useMutation({ mutationFn: async (selected: File) => { const parsed = JSON.parse(await selected.text()) as ConfigurationPortableDocument; return complianceService.configuration.import(parsed, createIdempotencyKey('configuration-import')); }, onSuccess: async () => { await query.refetch(); } }); if (query.isLoading) return <ComplianceSkeleton/>; return <CompliancePage title="Compliance configuration" description="Versioned, environment-specific rules with preview, audit history, rollout, export, and rollback." actions={<><input ref={(node) => { file.current = node; }} className="sr-only" type="file" accept="application/json" onChange={(e) => { const selected = e.target.files?.[0]; if (selected) importMutation.mutate(selected); }}/><Button variant="outline" onClick={() => file.current?.click()}><Upload className="mr-2 h-4 w-4"/>Import</Button><Button onClick={() => navigate(`${ROUTES.CONFIGURATION}/new?environment=${environment}`)}>New revision</Button></>}><label className="block max-w-xs text-sm font-medium">Environment<select className="mt-1 block w-full rounded-md border bg-background px-3 py-2" value={environment} onChange={(e) => { const n = new URLSearchParams(params); n.set('environment', e.target.value); setParams(n); }}><option>development</option><option>staging</option><option>production</option></select></label>{query.error ? <ComplianceError error={query.error} onRetry={() => void query.refetch()}/> : query.data?.data.length ? <SimpleTable headings={['Version', 'Environment', 'Status', 'Activated', 'Actions']}>{query.data.data.map((item) => <tr key={item.id}><td className="p-4">v{item.version}</td><td className="p-4">{item.environment}</td><td className="p-4"><ComplianceStatusBadge status={item.status}/></td><td className="p-4">{date(item.activated_at)}</td><td className="p-4"><Link className="underline" to={ROUTES.CONFIGURATION_DETAIL(item.id)}>Review</Link></td></tr>)}</SimpleTable> : <ComplianceEmpty title="No configuration revisions" description="Create a validated draft for this environment." action={<Button onClick={() => navigate(`${ROUTES.CONFIGURATION}/new?environment=${environment}`)}>Create revision</Button>}/>} {importMutation.error ? <ComplianceError error={importMutation.error}/> : null}</CompliancePage>; }

function ConfigurationEditor({ initial, environment, pending, error, onSubmit }: { readonly initial?: ComplianceConfigurationDocument; readonly environment: RuntimeEnvironment; readonly pending: boolean; readonly error?: Error | null; readonly onSubmit: (document: ComplianceConfigurationDocument) => void }) { const [doc, setDoc] = useState(initial ?? defaultDocument); const set = <K extends keyof ComplianceConfigurationDocument>(key: K, value: ComplianceConfigurationDocument[K]) => setDoc((current) => ({ ...current, [key]: value })); const rollout = doc.rollout.frameworks ?? { enabled: false, roles: [], cohorts: [] }; const setRollout = (next: typeof rollout) => set('rollout', { ...doc.rollout, frameworks: next }); const csv = (value: string) => value.split(',').map((item) => item.trim()).filter(Boolean); return <form className="space-y-6" onSubmit={(e) => { e.preventDefault(); onSubmit(doc); }}><p className="text-sm text-muted-foreground">Editing <strong>{environment}</strong>. The API validates the same safe limits before saving.</p><div className="grid gap-4 sm:grid-cols-2"><Input label="Policy code prefix" title="Uppercase prefix applied to policy codes" required maxLength={10} value={doc.policy_code_prefix} onChange={(e) => set('policy_code_prefix', e.target.value.toUpperCase())}/><Input label="Default review frequency (days)" title="Default cadence applied to new policies" type="number" min={1} max={3650} required value={doc.default_review_frequency_days} onChange={(e) => set('default_review_frequency_days', Number(e.target.value))}/><Input label="Policy expiry warning (days)" type="number" min={0} max={365} required value={doc.expiry_warning_days} onChange={(e) => set('expiry_warning_days', Number(e.target.value))}/><Input label="Evidence expiry warning (days)" type="number" min={0} max={365} required value={doc.evidence_warning_days} onChange={(e) => set('evidence_warning_days', Number(e.target.value))}/><Input label="Minimum assessment note length" title="Required rationale length for non-compliant decisions" type="number" min={0} max={2000} required value={doc.minimum_assessment_note_length} onChange={(e) => set('minimum_assessment_note_length', Number(e.target.value))}/><Input label="Bulk import row limit" type="number" min={1} max={10000} required value={doc.bulk_import_row_limit} onChange={(e) => set('bulk_import_row_limit', Number(e.target.value))}/><Input label="Regulation categories" title="Comma-separated allow-list" required value={doc.regulation_categories.join(', ')} onChange={(e) => set('regulation_categories', csv(e.target.value))}/><Input label="Rollout roles" title="Comma-separated role allow-list; blank means every role" value={(rollout.roles ?? []).join(', ')} onChange={(e) => setRollout({ ...rollout, roles: csv(e.target.value) })}/><Input label="Rollout cohorts" title="Comma-separated cohort allow-list; blank means every cohort" value={(rollout.cohorts ?? []).join(', ')} onChange={(e) => setRollout({ ...rollout, cohorts: csv(e.target.value) })}/><label className="flex items-center gap-2 text-sm"><input type="checkbox" checked={doc.allow_external_evidence_urls} onChange={(e) => set('allow_external_evidence_urls', e.target.checked)}/>Allow external evidence URLs</label><label className="flex items-center gap-2 text-sm"><input type="checkbox" checked={rollout.enabled ?? false} onChange={(e) => setRollout({ ...rollout, enabled: e.target.checked })}/>Enable framework capability</label></div>{error ? <ComplianceError error={error}/> : null}<Button disabled={pending}>{pending ? 'Saving draft…' : 'Save draft revision'}</Button></form>; }
export function EditConfigurationPage() { const { id } = useParams(); const [params] = useSearchParams(); const navigate = useNavigate(); const existing = useQuery({ queryKey: ['compliance', 'configuration-item', id], queryFn: () => complianceService.configuration.get(id ?? ''), enabled: Boolean(id) }); const environment = (existing.data?.environment ?? params.get('environment') ?? 'production') as RuntimeEnvironment; const mutation = useMutation({ mutationFn: (document: ComplianceConfigurationDocument) => id ? complianceService.configuration.update(id, { environment, document }) : complianceService.configuration.create({ environment, document }), onSuccess: (record) => navigate(ROUTES.CONFIGURATION_DETAIL(record.id)) }); if (id && existing.isLoading) return <ComplianceSkeleton/>; if (existing.error) return <CompliancePage title="Edit configuration" description="Configuration draft"><ComplianceError error={existing.error}/></CompliancePage>; return <CompliancePage title={id ? 'Edit configuration draft' : 'Create configuration revision'} description="Change bounded runtime behavior without a deployment." actions={<PageActions back={id ? ROUTES.CONFIGURATION_DETAIL(id) : ROUTES.CONFIGURATION}/>}><ComplianceSurface><ConfigurationEditor initial={existing.data?.document} environment={environment} pending={mutation.isPending} error={mutation.error} onSubmit={(document) => mutation.mutate(document)}/></ComplianceSurface></CompliancePage>; }

export function ConfigurationDetailPage() { const { id = '' } = useParams(); const query = useQuery({ queryKey: ['compliance', 'configuration-item', id], queryFn: () => complianceService.configuration.get(id), enabled: Boolean(id) }); const preview = useQuery({ queryKey: ['compliance', 'configuration-preview', id], queryFn: () => complianceService.configuration.preview(id), enabled: Boolean(id) }); const activate = useMutation({ mutationFn: () => complianceService.configuration.activate(id, { transition_key: createIdempotencyKey('configuration-activate') }), onSuccess: () => void query.refetch() }); const rollback = useMutation({ mutationFn: () => complianceService.configuration.rollback(id, { transition_key: createIdempotencyKey('configuration-rollback') }), onSuccess: () => void query.refetch() }); const exportDocument = async () => { const data = await complianceService.configuration.export(id); const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' }); const href = URL.createObjectURL(blob); const link = document.createElement('a'); link.href = href; link.download = `compliance-configuration-${id}.json`; link.click(); URL.revokeObjectURL(href); }; if (query.isLoading) return <ComplianceSkeleton/>; if (query.error) return <CompliancePage title="Configuration revision" description="Configuration details"><ComplianceError error={query.error}/></CompliancePage>; if (!query.data) return <CompliancePage title="Configuration revision" description="Configuration details"><ComplianceError error={new Error('Configuration revision not found.')}/></CompliancePage>; const item = query.data; const rollout = item.document.rollout.frameworks; return <CompliancePage title={`${item.environment} configuration v${item.version}`} description="Previewed, audited, portable tenant configuration." actions={<PageActions back={ROUTES.CONFIGURATION}>{item.status === 'draft' ? <><Link to={ROUTES.CONFIGURATION_EDIT(item.id)}><Button variant="outline">Edit draft</Button></Link><Button disabled={activate.isPending || preview.isLoading || Boolean(preview.error)} onClick={() => activate.mutate()}>{activate.isPending ? 'Activating…' : 'Activate'}</Button></> : <Button disabled={rollback.isPending} onClick={() => rollback.mutate()}>{rollback.isPending ? 'Rolling back…' : 'Rollback to this version'}</Button>}<Button variant="outline" onClick={() => void exportDocument()}><Download className="mr-2 h-4 w-4"/>Export</Button></PageActions>}><ComplianceSurface title="Revision"><DetailGrid><Detail label="Status"><ComplianceStatusBadge status={item.status}/></Detail><Detail label="Environment">{item.environment}</Detail><Detail label="Created">{date(item.created_at)}</Detail><Detail label="Activated">{date(item.activated_at)}</Detail><Detail label="Review cadence">Every {item.document.default_review_frequency_days} days</Detail><Detail label="Framework rollout">{rollout?.enabled ? 'Enabled' : 'Disabled'}</Detail></DetailGrid></ComplianceSurface><ComplianceSurface title="Preview diff and impact">{preview.isLoading ? <ComplianceSkeleton rows={2}/> : preview.error ? <ComplianceError error={preview.error} onRetry={() => void preview.refetch()}/> : preview.data ? <><ComplianceStatusBadge status="valid"/><div className="mt-4 grid gap-3 sm:grid-cols-4">{Object.entries(preview.data.affected).map(([key, count]) => <div key={key} className="rounded border p-3"><span className="text-xs uppercase text-muted-foreground">{key}</span><strong className="block text-xl">{count}</strong></div>)}</div>{preview.data.diff.length ? <ul className="mt-4 divide-y">{preview.data.diff.map((change) => <li key={change.field} className="grid gap-2 py-3 md:grid-cols-3"><strong>{change.field}</strong><code className="break-all text-xs">{JSON.stringify(change.before)}</code><code className="break-all text-xs">{JSON.stringify(change.after)}</code></li>)}</ul> : <p className="mt-4 text-sm text-muted-foreground">No effective changes.</p>}</> : null}</ComplianceSurface>{activate.error || rollback.error ? <ComplianceError error={(activate.error ?? rollback.error) as Error}/> : null}</CompliancePage>; }

export function ComplianceActivityPage() { const [params, setParams] = useSearchParams(); const filters = { page: Number(params.get('page') ?? 1), page_size: 25, entity_type: params.get('entity_type') ?? undefined, correlation_id: params.get('correlation_id') ?? undefined, ordering: '-occurred_at' }; const query = useQuery({ queryKey: ['compliance', 'activity', filters], queryFn: () => complianceService.activity(filters) }); if (query.isLoading) return <ComplianceSkeleton/>; return <CompliancePage title="Compliance activity" description="Immutable actor, action, time, correlation, and redacted before/after history." actions={<PageActions back={ROUTES.DASHBOARD}/>}><ListToolbar name="activity" params={params} setParams={setParams}/>{query.error ? <ComplianceError error={query.error} onRetry={() => void query.refetch()}/> : query.data?.data.length ? <ol className="space-y-3">{query.data.data.map((item) => <li key={item.id} className="rounded-xl border bg-card p-4"><div className="flex flex-wrap justify-between gap-2"><span><strong>{item.action}</strong> · {item.entity_type}</span><time className="text-sm text-muted-foreground">{date(item.occurred_at)}</time></div><p className="mt-2 text-sm">{item.reason || 'No reason supplied.'}</p><p className="mt-2 font-mono text-xs text-muted-foreground">Correlation: {item.correlation_id}</p><details className="mt-3"><summary className="cursor-pointer text-sm underline">Redacted change snapshot</summary><pre className="mt-2 overflow-auto rounded bg-muted p-3 text-xs">{JSON.stringify({ before: item.before, after: item.after }, null, 2)}</pre></details></li>)}</ol> : <ComplianceEmpty title="No activity" description="Governed compliance mutations will appear here."/>}</CompliancePage>; }
